const md = $('Mira - OpenAI').item.json.message.content;
const now = new Date();
const dateStr = now.toLocaleDateString('en-GB', { day:'numeric', month:'long', year:'numeric' });

let html = md
  .replace(/^---$/gm, '<hr style="border:none;border-top:1px solid #E0E0E0;margin:20px 0">')
  .replace(/^## (.+)$/gm, '<h2 style="color:#333333;font-family:Arial;font-size:16px;font-weight:bold;border-bottom:2px solid #E0E0E0;padding-bottom:6px;margin-top:24px">$1</h2>')
  .replace(/^### (.+)$/gm, '<h3 style="color:#555555;font-family:Arial;font-size:14px;font-weight:bold;margin-top:16px">$1</h3>')
  .replace(/\*\*(.+?)\*\*/g, '<strong>$1</strong>')
  .replace(/^- (.+)$/gm, '<li style="font-family:Arial;font-size:14px;color:#333;padding:3px 0">$1</li>')
  .replace(/(<li[^>]*>.*<\/li>\n?)+/gs, '<ul style="margin:10px 0;padding-left:20px">$&</ul>')
  .replace(/^\|(.+)\|$/gm, (match) => {
    const cells = match.split('|').filter(c => c.trim() !== '');
    return '<tr>' + cells.map(c => `<td style="border:1px solid #E0E0E0;padding:8px 12px;font-family:Arial;font-size:13px;color:#333">${c.trim()}</td>`).join('') + '</tr>';
  })
  .replace(/<tr>(<td[^>]*>[\s\-:]+<\/td>)+<\/tr>/g, '')
  .replace(/(<tr>.*<\/tr>\n?)+/gs, (match) => {
    const rows = match.trim().split('\n');
    const header = rows[0].replace(/<td/g, '<td style="background:#F5F5F5;font-weight:bold;border:1px solid #E0E0E0;padding:8px 12px;font-family:Arial;font-size:13px;color:#333"');
    const body = rows.slice(1).join('\n');
    return `<table style="border-collapse:collapse;width:100%;margin:15px 0">${header}${body}</table>`;
  })
  .replace(/\n\n/g, '<br><br>')
  .replace(/\n/g, '<br>');

const emailHtml = `<!DOCTYPE html><html><body style="font-family:Arial;max-width:800px;margin:0 auto;padding:20px;color:#333;background:#FFFFFF">
<div style="background:#F8F8F8;border-left:4px solid #555555;padding:15px 20px;margin-bottom:20px">
<p style="margin:0;font-size:18px;font-weight:bold;color:#222">Mira Project Intelligence Report</p>
<p style="margin:4px 0 0;font-size:12px;color:#777">Generated by Mira for Nexora Pvt. Ltd. | ${dateStr}</p>
</div>
<div style="padding:0 5px">
${html}
</div>
<div style="margin-top:30px;padding-top:15px;border-top:1px solid #E0E0E0">
<p style="font-size:11px;color:#999;margin:0">This report was generated automatically by Mira. Review before sharing externally.</p>
</div>
</body></html>`;

return [{ json: { emailHtml, dateStr } }];
